<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>{{ $receipt->registration->registration_number }} Receipt</title><style>body{margin:0;background:#f5f7fb;color:#1f2a37;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI",Arial,sans-serif}.wrap{max-width:1100px;margin:0 auto;padding:22px 16px}.grid{display:grid;grid-template-columns:1fr 1fr;gap:14px}.card{background:white;border:1px solid #d9dee8;border-radius:8px;padding:20px;margin-bottom:14px;box-shadow:0 4px 16px rgba(22,47,83,.05)}h1,h2,h3{color:#153764}.btn{border:0;border-radius:6px;padding:10px 14px;font-weight:900;text-decoration:none;display:inline-flex;background:#153764;color:white;cursor:pointer}.btn.light{background:white;color:#153764;border:1.5px solid #d9dee8}.btn.danger{background:#b42318}table{width:100%;border-collapse:collapse}td,th{padding:8px 0;border-bottom:1px solid #edf0f5;font-size:13px;text-align:left;vertical-align:top}td:first-child{width:34%;color:#667085}label{display:flex;flex-direction:column;gap:6px;margin-bottom:10px;font-weight:800}input,textarea,select{border:1.5px solid #cbd3df;border-radius:6px;padding:9px 11px;font:inherit}.notice{background:#e8f6ef;color:#237a4f;padding:10px 12px;border-radius:8px;margin-bottom:12px}.error{background:#fff0ee;color:#b42318;padding:10px 12px;border-radius:8px;margin-bottom:12px}@media(max-width:840px){.grid{grid-template-columns:1fr}}</style></head><body><main class="wrap">@if(session('status'))<div class="notice">{{ session('status') }}</div>@endif @if($errors->any())<div class="error">{{ $errors->first() }}</div>@endif<div class="card"><h1>{{ $receipt->registration->registration_number }} Receipt</h1><a class="btn light" href="{{ route('admin.receipts.index') }}">Back</a></div><div class="grid"><div class="card"><h2>Receipt</h2><table><tr><td>Status</td><td>{{ $receipt->status }}</td></tr><tr><td>Type</td><td>{{ $receipt->receipt_type }}</td></tr><tr><td