 name="buyer_phone" value="{{ old('buyer_phone',$receipt->buyer_phone) }}"></label><label>Company<input name="company_name" value="{{ old('company_name',$receipt->company_name) }}"></label><label>GUI / Tax ID<input name="gui_tax_id" value="{{ old('gui_tax_id',$receipt->gui_tax_id) }}"></label><label>Notes<textarea name="notes">{{ old('notes',$receipt->notes) }}</textarea></label><button class="btn" type="submit">Save</button></form></div><div class="card"><h2>Actions</h2><form method="POST" action="{{ route('admin.receipts.issue',$receipt) }}">@csrf<label>Receipt Number<input name="receipt_number" value="{{ old('receipt_number',$receipt->receipt_number) }}"></label><label>Notes<textarea name="notes"></textarea></label><button class="btn" type="submit">Mark Issued</button></form><form method="POST" action="{{ route('admin.receipts.status',$receipt) }}">@csrf<label>Status<select name="status">@foreach(['requested','pending_issue','issued','sent','failed','cancelled','voided'] as $status)<option value="{{ $status }}">{{ $status }}</option>@endforeach</select></label><label>Notes<textarea name="notes"></textarea></label><button class="btn light" type="submit">Update Status</button></form><form method="POST" action="{{ route('admin.receipts.send',$receipt) }}">@csrf<button class="btn light" type="submit">Resend Receipt Email</button></form><form method="POST" action="{{ route('admin.receipts.auto-issue',$receipt) }}">@csrf<button class="btn light" type="submit">Sandbox Auto Issue</button></form></div></div><div class="grid"><div class="card"><h2>Receipt History</h2><table><thead><tr><th>Event</th><th>Old</th><th>New</th><th>Time</th></tr></thead><tbody>@foreach($receipt->logs->sortByDesc('created_at') as $log)<tr><td>{{ $log->event_type }}</td><td>{{ $log->old_status }}</td><td>{{ $log->new_status }}</td><td>{{ $log->created_at->format('Y-m-d H:i') }}</td></tr>@endforeach</tbody></table></div><div class="card"><h2>E-Invoice Transactions</h2><table><thead><tr><th>Provider</th><th>Status</th><th>Invoice</th><th>Error</th></tr></thead><tbody>@foreach($receipt->transactions as $transaction)<tr><td>{{ $transaction->provider }}</td><td>{{ $transaction->provider_status }}</td><td>{{ $transaction->provider_invoice_number }}</td><td>{{ $transaction->error_message }}</td></tr>@endforeach</tbody></table></div></div></main></body></html>
